import{_ as s,o as n,c as e,a2 as l}from"./chunks/framework.BnBoz4Zl.js";const i="/anjian-workbuddy-bluebook-site/assets/001_image_J9BUbk5hHo.f3JGw1H0.png",b=JSON.parse('{"title":"第 12 章 从整理桌面文件这些小事做起","description":"桌面发票是典型的“电脑在替人承受混乱”的场景：电子发票、截图、PDF、微信下载文件、邮件附件混在一起，命名方式各不相同。人不在电脑前时，最烦的不是不知道怎么报销，而是不知道哪几张发票已经在电脑里、哪些字段还缺、哪些文件可能重复。","frontmatter":{},"headers":[],"relativePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 12 章 从整理桌面文件这些小事做起/index.md","filePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 12 章 从整理桌面文件这些小事做起/index.md","lastUpdated":1784771354000}'),t={name:"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 12 章 从整理桌面文件这些小事做起/index.md"};function p(o,a,r,d,c,h){return n(),e("div",null,[...a[0]||(a[0]=[l(`<h1 id="第-12-章-从整理桌面文件这些小事做起" tabindex="-1">第 12 章 从整理桌面文件这些小事做起 <a class="header-anchor" href="#第-12-章-从整理桌面文件这些小事做起" aria-label="Permalink to &quot;第 12 章 从整理桌面文件这些小事做起&quot;">​</a></h1><h2 id="整理桌面发票-不再回电脑前翻文件" tabindex="-1">整理桌面发票，不再回电脑前翻文件 <a class="header-anchor" href="#整理桌面发票-不再回电脑前翻文件" aria-label="Permalink to &quot;整理桌面发票，不再回电脑前翻文件&quot;">​</a></h2><p>桌面发票是典型的“电脑在替人承受混乱”的场景：电子发票、截图、PDF、微信下载文件、邮件附件混在一起，命名方式各不相同。人不在电脑前时，最烦的不是不知道怎么报销，而是不知道哪几张发票已经在电脑里、哪些字段还缺、哪些文件可能重复。</p><h3 id="场景痛点" tabindex="-1">场景痛点 <a class="header-anchor" href="#场景痛点" aria-label="Permalink to &quot;场景痛点&quot;">​</a></h3><ul><li>发票散落在桌面、下载目录、微信文件目录，格式可能是 PDF、JPG、PNG。</li><li>文件名经常只叫“发票.pdf”“image.png”“微信图片_2026xxxx.jpg”。</li><li>报销真正需要的是结构化字段：抬头、税号、金额、开票日期、发票号码、销售方。</li><li>远程批量整理最怕误删、覆盖、移动原件，导致后面找不回来。</li></ul><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请帮我整理电脑里的发票，但不要删除、移动或覆盖原文件。</span></span>
<span class="line"><span>扫描范围只包括桌面、Downloads 和微信文件接收目录，时间范围为最近 30 天。</span></span>
<span class="line"><span>候选条件：文件名包含“发票”“电子发票”“invoice”，或内容识别为发票的 PDF、JPG、PNG。</span></span>
<span class="line"><span>第一步先返回候选清单和数量。</span></span>
<span class="line"><span>第二步识别抬头、税号、金额、开票日期、发票号码、销售方、文件路径。</span></span>
<span class="line"><span>第三步生成 invoice-ledger.xlsx，并列出“重复发票”和“无法识别字段”的人工确认清单。</span></span></code></pre></div><p>执行后仅新增台账文件，桌面原发票不移动、不改名、不删除</p><p><img src="`+i+`" alt="" loading="lazy"></p><h2 id="合成示例" tabindex="-1">合成示例 <a class="header-anchor" href="#合成示例" aria-label="Permalink to &quot;合成示例&quot;">​</a></h2><blockquote><p>质量门禁补录：一个虚构专题目录中有 32 个文件，其中同名 4 个、状态不明 3 个。WorkBuddy 应先生成清单与建议目录，不能仅凭“final/最终”等文件名直接删除其他版本。</p></blockquote><h3 id="可复制任务模板" tabindex="-1">可复制任务模板 <a class="header-anchor" href="#可复制任务模板" aria-label="Permalink to &quot;可复制任务模板&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请只读检查当前工作目录，暂时不要移动、删除、覆盖或重命名任何文件。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>目标：{整理/交接/归档/迁移}</span></span>
<span class="line"><span>分类规则：{规则或“请先建议”}</span></span>
<span class="line"><span>正式成果判断依据：{审批、签署、盖章、确认记录等}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>先输出：1) 文件清单与异常；2) 可能的重复与版本关系；3) 建议目录；4) 拟操作预览与冲突处理；5) 无法判断、需人工确认的文件。未经我确认，不执行写入操作。</span></span></code></pre></div><h2 id="输出物与验收标准" tabindex="-1">输出物与验收标准 <a class="header-anchor" href="#输出物与验收标准" aria-label="Permalink to &quot;输出物与验收标准&quot;">​</a></h2><ul><li>文件清单完整，异常有标记。</li><li>每项写操作都有预览与确认记录。</li><li>原件未被覆盖，失败可回退。</li><li>归档后数量、路径与抽样内容核对一致。</li></ul><h2 id="常见弯路与安全边界" tabindex="-1">常见弯路与安全边界 <a class="header-anchor" href="#常见弯路与安全边界" aria-label="Permalink to &quot;常见弯路与安全边界&quot;">​</a></h2><ul><li>只按修改时间认定终稿，会忽略审批与签署依据。</li><li>一上来批量重命名，容易破坏外部引用。</li><li>删除、覆盖与外部归档必须人工确认；可复用资产包括文件清单、目录模板、变更预览与处理日志。</li></ul>`,16)])])}const x=s(t,[["render",p]]);export{b as __pageData,x as default};
